((i,r)=>{i.behaviors.toc={attach:e=>{r("toc",".toc",e).forEach(t=>{const o=t.dataset.contentSelector,n=t.dataset.headingLevels,l=t.dataset.ignoreSelector||"";if(!o||!n)return;const a=n.split(",").join(", "),s=document.querySelector(o);if(!s)return;s.querySelectorAll(a).forEach(c=>{c.id||(c.id=c.textContent.trim().toLowerCase().replace(/[^a-z0-9]+/g,"-").replace(/(^-|-$)/g,""))});const d=t.querySelector(".toc__body")||t;tocbot.init({tocElement:d,contentSelector:o,headingSelector:a,ignoreSelector:l})})},detach:e=>{r.remove("toc",".toc",e).forEach(()=>{tocbot.destroy()})}}})(Drupal,once);
